// Filtrar apenas relatórios com dados válidos
const reports = $input.all();
return reports.filter(item => {
  const data = item.json;
  return data.id && data.mensagem_template && data.recebedor_numero;
});

const report = $input.first().json;

// Verificar se o webhook retornou sucesso
const webhookOutput = $input.first();
const statusCode = webhookOutput.json?.statusCode || webhookOutput.statusCode;

if (statusCode >= 400) {
  // Se houve erro no webhook, NÃO recalcular proximo_envio
  return [{ json: { ...report, skip_update: true, webhook_error: true, webhook_status: statusCode } }];
}

// Calcular proximo_envio apenas se NÃO for manual
const frequencia = report.frequencia;
const horario = report.horario_envio;
const diasSemana = report.dias_semana;

if (frequencia === 'manual') {
  // Manual: não recalcular, apenas marcar para não atualizar
  return [{ json: { ...report, skip_update: true, frequencia_manual: true } }];
}

// Calcular novo proximo_envio baseado na frequencia
const agora = new Date();
const [horas, minutos] = horario.split(':').map(Number);

let proximoEnvio;

if (frequencia === 'diario') {
  proximoEnvio = new Date(agora);
  proximoEnvio.setDate(proximoEnvio.getDate() + 1);
  proximoEnvio.setHours(horas, minutos, 0, 0);
} else if (frequencia === 'semanal') {
  // Encontrar o próximo dia da semana válido
  if (diasSemana && diasSemana.length > 0) {
    const diasNums = diasSemana.map(Number).sort((a, b) => a - b);
    let tentativa = new Date(agora);
    tentativa.setDate(agora.getDate() + 1);
    tentativa.setHours(horas, minutos, 0, 0);
    let encontrou = false;
    for (let i = 0; i < 7; i++) {
      if (diasNums.includes(tentativa.getDay())) {
        encontrou = true;
        break;
      }
      tentativa.setDate(tentativa.getDate() + 1);
    }
    proximoEnvio = tentativa;
  } else {
    // Sem dias_semana definidos, somar 7 dias
    proximoEnvio = new Date(agora);
    proximoEnvio.setDate(proximoEnvio.getDate() + 7);
    proximoEnvio.setHours(horas, minutos, 0, 0);
  }
} else if (frequencia === 'mensal') {
  proximoEnvio = new Date(agora);
  proximoEnvio.setMonth(proximoEnvio.getMonth() + 1);
  proximoEnvio.setHours(horas, minutos, 0, 0);
}

const novoProximoEnvio = proximoEnvio.toISOString();

return [{ json: { ...report, novo_proximo_envio: novoProximoEnvio, skip_update: false } }];

// Separar relatórios que precisam de update dos que não precisam
const items = $input.all();
const updates = [];
const skips = [];

for (const item of items) {
  if (item.json.skip_update) {
    skips.push({ json: { report_id: item.json.id, skipped: true, reason: item.json.webhook_error ? 'webhook_error' : 'frequencia_manual' } });
  } else {
    updates.push({ json: { id: item.json.id, proximo_envio: item.json.novo_proximo_envio } });
  }
}

return updates;

// Registrar logs dos relatórios disparados
const items = $input.all();

for (const item of items) {
  const report = item.json;
  console.log(`Relatório ${report.id || report.report_id} disparado com sucesso`);

  if (report.skip_update) {
    if (report.webhook_error) {
      console.log(`  ⚠ Erro no webhook - proximo_envio NÃO atualizado (tentará novamente em 15min)`);
    } else {
      console.log(`  ℹ Frequência manual - proximo_envio NÃO recalculado`);
    }
  } else {
    console.log(`  ✓ proximo_envio atualizado para: ${report.novo_proximo_envio || report.proximo_envio}`);
  }
}

return items;
